namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string documentText, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class ExtractiveSummaryService : IDocumentSummaryService
{
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        var scored = sentences
            .Select((sentence, index) => new { sentence, score = ScoreSentence(sentence, index, sentences) })
            .OrderByDescending(s => s.score)
            .Take(maxSentences)
            .OrderBy(s => Array.IndexOf(sentences, s.sentence))
            .Select(s => s.sentence);

        return string.Join(" ", scored);
    }

    private static string[] SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text.Trim())
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .Select(s => s.Trim())
            .ToArray();
    }

    private static double ScoreSentence(string sentence, int index, string[] allSentences)
    {
        var words = sentence.Split(' ', StringSplitOptions.RemoveEmptyEntries);
        double lengthScore = Math.Min(words.Length / 20.0, 1.0);

        // Boost earlier sentences (lead bias)
        double positionScore = 1.0 / (index + 1);

        // Word frequency scoring
        var wordFrequency = allSentences
            .SelectMany(s => s.Split(' ', StringSplitOptions.RemoveEmptyEntries))
            .Select(w => w.ToLowerInvariant())
            .GroupBy(w => w)
            .ToDictionary(g => g.Key, g => g.Count());

        double frequencyScore = words
            .Select(w => wordFrequency.GetValueOrDefault(w.ToLowerInvariant(), 0))
            .Average();

        return (lengthScore * 0.2) + (positionScore * 0.4) + (frequencyScore * 0.4);
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceSplitter();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummaryService summaryService) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText is required and cannot be empty.");

        var summary = summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

